                                onChange={e => setSearch(e.target.value)}
                            />
                            {search && (
                                <button onClick={() => { setSearch(""); searchInputRef.current?.focus(); }} className="absolute right-2 top-1/2 -translate-y-1/2 p-1 text-slate-400 hover:text-red-500 transition-colors">
                                    <Icon name="X" size={14} />
                                </button>
